func (r *UserRepo) GetByID(ctx context.Context, id string) (*User, error) {
    const op = "UserRepo.GetByID"
    var u User
    err := r.db.QueryRowContext(ctx, getUserSQL, id).Scan(&u.ID, &u.Email)
    if err != nil {
        if errors.Is(err, sql.ErrNoRows) {
            return nil, fmt.Errorf("%s: %w", op, apperror.ErrNotFound)
        }
        return nil, fmt.Errorf("%s: %w", op, err)
    }
    return &u, nil
}

func (h *Handler) GetUser(w http.ResponseWriter, r *http.Request) {
    u, err := h.svc.GetUser(r.Context(), chi.URLParam(r, "id"))
    if err != nil {
        h.log.Error("get_user_failed", "err", err, "path", r.URL.Path)
        http.Error(w, err.Error(), apperror.HTTPStatus(err))
        return
    }
    json.NewEncoder(w).Encode(u)
}

